using System;using System.Collections.Generic;using System.Linq;using SensCalibr8.Data.Persistence;
namespace SensCalibr8.Data.Repositories
{
 public sealed class TrainingCycleState
 {public TrainingCycleState(long profileId,long cycleId,long cycleNumber,long phaseHistoryId,long candidateId,double bestEdpi,double sensitivity,int sessionCount,int completeBatteryCount,double? latestScore,string latestGrade){ProfileId=profileId;CycleId=cycleId;CycleNumber=cycleNumber;PhaseHistoryId=phaseHistoryId;CandidateId=candidateId;BestEdpi=bestEdpi;Sensitivity=sensitivity;SessionCount=sessionCount;CompleteBatteryCount=completeBatteryCount;LatestScore=latestScore;LatestGrade=latestGrade;}public long ProfileId{get;}public long CycleId{get;}public long CycleNumber{get;}public long PhaseHistoryId{get;}public long CandidateId{get;}public double BestEdpi{get;}public double Sensitivity{get;}public int SessionCount{get;}public int CompleteBatteryCount{get;}public double? LatestScore{get;}public string LatestGrade{get;}}
 public sealed class CycleCheckpointRecord
 {public CycleCheckpointRecord(long id,long profileId,long cycleId,long sourceHistoryId,double bestEdpi,int sessions,int batteries,double score,string grade,string version,string date){Id=id;ProfileId=profileId;CycleId=cycleId;SourceHistoryId=sourceHistoryId;BestEdpi=bestEdpi;TrainingSessionCount=sessions;CompletedTrainingBatteryCount=batteries;PerformanceScore=score;FinalGrade=grade;ContractVersion=version;CheckpointDate=date;}public long Id{get;}public long ProfileId{get;}public long CycleId{get;}public long SourceHistoryId{get;}public double BestEdpi{get;}public int TrainingSessionCount{get;}public int CompletedTrainingBatteryCount{get;}public double PerformanceScore{get;}public string FinalGrade{get;}public string ContractVersion{get;}public string CheckpointDate{get;}}
 public sealed class RecalibrationEventRecord
 {public RecalibrationEventRecord(long sourceCycleId,long destinationCycleId,double baselineEdpi){SourceCycleId=sourceCycleId;DestinationCycleId=destinationCycleId;BaselineEdpi=baselineEdpi;}public long SourceCycleId{get;}public long DestinationCycleId{get;}public double BaselineEdpi{get;}}
 public sealed class ContinuousCycleRepository
 {
  private readonly RepositoryExecution execution;public ContinuousCycleRepository(SqliteConnectionFactory factory,IDataFailureReporter reporter=null){execution=new RepositoryExecution(factory,reporter);}
  public TrainingCycleState RequireTrainingState(long profileId,long cycleId){return execution.Read("read continuous cycle state",c=>{var rows=c.Query(@"SELECT cy.cycle_number,h.id history_id,h.winner_edpi,p.id candidate_id,p.sensitivity_value,
(SELECT COUNT(*) FROM sessions s JOIN protocol_batteries b ON b.id=s.battery_id WHERE b.profile_id=@profile AND b.cycle_id=@cycle AND b.candidate_id=p.id AND b.purpose='training') sessions,
(SELECT COUNT(*) FROM protocol_batteries b WHERE b.profile_id=@profile AND b.cycle_id=@cycle AND b.candidate_id=p.id AND b.purpose='training' AND b.completed_date IS NOT NULL) batteries,
(SELECT st.avg_performance_score FROM sensitivity_tests st JOIN protocol_batteries b ON b.id=st.battery_id WHERE b.profile_id=@profile AND b.cycle_id=@cycle AND b.candidate_id=p.id AND b.purpose='training' AND b.completed_date IS NOT NULL ORDER BY st.id DESC LIMIT 1) score,
(SELECT st.grade FROM sensitivity_tests st JOIN protocol_batteries b ON b.id=st.battery_id WHERE b.profile_id=@profile AND b.cycle_id=@cycle AND b.candidate_id=p.id AND b.purpose='training' AND b.completed_date IS NOT NULL ORDER BY st.id DESC LIMIT 1) grade
FROM cycles cy JOIN phase_history h ON h.cycle_id=cy.id AND h.profile_id=cy.profile_id AND h.phase_number=3 JOIN protocol_candidates p ON p.cycle_id=cy.id AND p.profile_id=cy.profile_id AND p.phase=3 AND p.edpi=h.winner_edpi WHERE cy.id=@cycle AND cy.profile_id=@profile;",new Dictionary<string,object>{{"@profile",profileId},{"@cycle",cycleId}});if(rows.Count!=1)throw new InvalidOperationException("A unique Phase 3 Winner candidate is required for continuous training.");var r=rows[0];return new TrainingCycleState(profileId,cycleId,Convert.ToInt64(r["cycle_number"]),Convert.ToInt64(r["history_id"]),Convert.ToInt64(r["candidate_id"]),Convert.ToDouble(r["winner_edpi"]),Convert.ToDouble(r["sensitivity_value"]),Convert.ToInt32(r["sessions"]),Convert.ToInt32(r["batteries"]),r["score"]==null?(double?)null:Convert.ToDouble(r["score"]),r["grade"]==null?null:Convert.ToString(r["grade"]));});}
  public ProtocolBatteryRecord CreateTrainingBattery(TrainingCycleState state,string purpose,string date){if(state==null)throw new ArgumentNullException(nameof(state));return execution.Write("create training battery",c=>{c.Execute(@"INSERT INTO protocol_batteries(profile_id,cycle_id,candidate_id,sensitivity_value,phase,purpose,started_date,completed_date) VALUES(@profile,@cycle,@candidate,@sensitivity,3,@purpose,@date,NULL);",new Dictionary<string,object>{{"@profile",state.ProfileId},{"@cycle",state.CycleId},{"@candidate",state.CandidateId},{"@sensitivity",state.Sensitivity},{"@purpose",purpose},{"@date",date}});return new ProtocolBatteryRecord(c.LastInsertRowId(),state.ProfileId,state.CycleId,state.CandidateId,state.Sensitivity,3,purpose,date,null);});}
  public CycleCheckpointRecord CreateCheckpoint(TrainingCycleState state,int minimum,int maximum,string version,string date){if(state==null)throw new ArgumentNullException(nameof(state));return execution.Write("create cycle checkpoint",c=>{if(state.SessionCount<minimum||state.SessionCount>maximum||!state.LatestScore.HasValue||string.IsNullOrWhiteSpace(state.LatestGrade))throw new InvalidOperationException("Training checkpoint requires the accepted session count and a latest complete scored Grade.");c.Execute(@"INSERT INTO cycle_checkpoints(profile_id,cycle_id,source_phase_history_id,best_edpi,training_session_count,completed_training_battery_count,performance_score,final_grade,contract_version,checkpoint_date) VALUES(@profile,@cycle,@history,@edpi,@sessions,@batteries,@score,@grade,@version,@date);",new Dictionary<string,object>{{"@profile",state.ProfileId},{"@cycle",state.CycleId},{"@history",state.PhaseHistoryId},{"@edpi",state.BestEdpi},{"@sessions",state.SessionCount},{"@batteries",state.CompleteBatteryCount},{"@score",state.LatestScore.Value},{"@grade",state.LatestGrade},{"@version",version},{"@date",date}});return new CycleCheckpointRecord(c.LastInsertRowId(),state.ProfileId,state.CycleId,state.PhaseHistoryId,state.BestEdpi,state.SessionCount,state.CompleteBatteryCount,state.LatestScore.Value,state.LatestGrade,version,date);});}
  public IReadOnlyList<CycleCheckpointRecord> ListCheckpoints(long profileId){return execution.Read("list cycle checkpoints",c=>c.Query("SELECT cp.*,cy.cycle_number FROM cycle_checkpoints cp JOIN cycles cy ON cy.id=cp.cycle_id WHERE cp.profile_id=@profile ORDER BY cy.cycle_number;",new Dictionary<string,object>{{"@profile",profileId}}).Select(Map).ToArray());}
  public RecalibrationEventRecord BeginRecalibration(CycleCheckpointRecord source,CycleRecord destination,IReadOnlyList<ProtocolCandidateCreateRequest> requests,string version,string date){if(source==null||destination==null||requests==null||requests.Count==0)throw new ArgumentException("Recalibration inputs are required.");return execution.Write("begin plateau recalibration",c=>{using SqliteTransaction t=c.BeginImmediateTransaction();c.Execute("INSERT INTO cycles(profile_id,cycle_number,start_date,end_date,outcome) VALUES(@profile,@number,@date,NULL,'plateau_recalibration_started');",new Dictionary<string,object>{{"@profile",destination.ProfileId},{"@number",destination.CycleNumber},{"@date",destination.StartDate}});long id=c.LastInsertRowId();foreach(var q in requests){var x=q.Candidate;c.Execute("INSERT INTO protocol_candidates(profile_id,cycle_id,phase,edpi,sensitivity_value,generation_rule,created_date) VALUES(@profile,@cycle,@phase,@edpi,@sensitivity,@rule,@date);",new Dictionary<string,object>{{"@profile",x.ProfileId},{"@cycle",id},{"@phase",x.Phase},{"@edpi",x.Edpi},{"@sensitivity",x.SensitivityValue},{"@rule",x.GenerationRule},{"@date",x.CreatedDate}});long candidate=c.LastInsertRowId();foreach(var s in q.Sources)c.Execute("INSERT INTO protocol_candidate_sources(candidate_id,anchor_edpi,offset_percent,pre_floor_edpi,floor_applied) VALUES(@id,@anchor,@offset,@pre,@floor);",new Dictionary<string,object>{{"@id",candidate},{"@anchor",s.AnchorEdpi},{"@offset",s.OffsetPercent},{"@pre",s.PreFloorEdpi},{"@floor",s.FloorApplied}});}c.Execute("INSERT INTO recalibration_events(profile_id,source_cycle_id,destination_cycle_id,source_phase_history_id,source_checkpoint_id,baseline_edpi,contract_version,triggered_date) VALUES(@profile,@source,@destination,@history,@checkpoint,@baseline,@version,@date);",new Dictionary<string,object>{{"@profile",source.ProfileId},{"@source",source.CycleId},{"@destination",id},{"@history",source.SourceHistoryId},{"@checkpoint",source.Id},{"@baseline",source.BestEdpi},{"@version",version},{"@date",date}});t.Commit();return new RecalibrationEventRecord(source.CycleId,id,source.BestEdpi);});}
  private static CycleCheckpointRecord Map(IReadOnlyDictionary<string,object> r)=>new CycleCheckpointRecord(Convert.ToInt64(r["id"]),Convert.ToInt64(r["profile_id"]),Convert.ToInt64(r["cycle_id"]),Convert.ToInt64(r["source_phase_history_id"]),Convert.ToDouble(r["best_edpi"]),Convert.ToInt32(r["training_session_count"]),Convert.ToInt32(r["completed_training_battery_count"]),Convert.ToDouble(r["performance_score"]),Convert.ToString(r["final_grade"]),Convert.ToString(r["contract_version"]),Convert.ToString(r["checkpoint_date"]));
 }
}
